import{c as o,Q as t,j as a,m as r}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"How do I promote someone to Admin?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/portal/promote-to-admin.md","filePath":"guide/recipes/portal/promote-to-admin.md","lastUpdated":1778912818000}'),s={name:"guide/recipes/portal/promote-to-admin.md"};function n(i,e,l,d,m,c){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="how-do-i-promote-someone-to-admin" tabindex="-1">How do I promote someone to Admin? <a class="header-anchor" href="#how-do-i-promote-someone-to-admin" aria-label="Permalink to &quot;How do I promote someone to Admin?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Owner</strong> only</p></div><p>Only the Owner can grant the Admin role. Admins can grant Billing, Viewer, or Member, but never another Admin.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>Users</strong> in the sidebar.</li><li>Click the row of the user you want to promote.</li><li>Change the <strong>Portal Role</strong> dropdown to <strong>Admin</strong>.</li><li>The change saves automatically.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>The user now has Admin permissions across your customer — they can manage users, tenants, settings, auth config, webhooks, and service accounts. They still can&#39;t promote anyone else to Admin or change another Admin&#39;s role.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./transfer-ownership">How do I transfer ownership of my customer?</a></li><li><a href="./change-user-role">How do I change a user&#39;s portal role?</a></li><li><a href="./../../concepts/roles-and-permissions">Roles &amp; Permissions reference</a></li></ul>',9)])])}const u=o(s,[["render",n]]);export{p as __pageData,u as default};
